    {
      "id": "d2",
      "decision": "Use a new error code 'conditional_range_violation' at HTTP 400 with admissible range {min, max} in error details.",
      "based_on": ["q3"],
      "alternatives_rejected": [
        "Reuse 'invalid_probability_edit' — rejected because it conflates payload normalization with semantic range validation",
        "Reuse 'invalid_structure_preserving_edit' — rejected because T551 boundary freeze explicitly owns that code for base-slice preservation"
      ],
      "reversibility": "easy"
    },
